#!/usr/bin/env bash
# RunAI job submission script — generated by run-experiment skill
# Project:  {PROJECT}
# Created:  {DATE}
# Commit:   {COMMIT}
#
# Run this script to submit the job: bash {SCRIPT_NAME}
# Monitor:  runai list
# Logs:     runai logs {JOB_NAME} -f
# Shell:    runai bash {JOB_NAME}

set -euo pipefail

JOB_NAME="{JOB_NAME}"
IMAGE="{IMAGE}"
PROJECT="{RUNAI_PROJECT}"
GPUS={GPUS}
CPU={CPUS}
MEMORY="{MEM}"

echo "Submitting RunAI job: $JOB_NAME"
echo "  Image:   $IMAGE"
echo "  Project: $PROJECT"
echo "  GPUs:    $GPUS"
echo "  Commit:  {COMMIT}"

runai submit "$JOB_NAME" \
  --image "$IMAGE" \
  --project "$PROJECT" \
  --gpu "$GPUS" \
  --cpu "$CPU" \
  --memory "$MEMORY" \
  {PVC_FLAGS} \
  -e GIT_COMMIT={COMMIT} \
  -e EXPERIMENT_NAME="$JOB_NAME" \
  -- {RUN_COMMAND}

echo ""
echo "Submitted. Commands:"
echo "  Watch:  runai list"
echo "  Logs:   runai logs $JOB_NAME -f"
echo "  Shell:  runai bash $JOB_NAME"
echo "  Delete: runai delete $JOB_NAME"
